class Solution {
    public boolean isSubsequence(String s, String t) {
        if ((s.length() == 0 && t.length() != 0)) {
            return true;
        } 
        if (s.length() == 0 && t.length() == 0) {
            return true;
        }
        int p1 = 0;
        for (int i = 0; i < t.length(); i++) {
            if (s.charAt(p1) == t.charAt(i)) {
                p1++;
            }
            if (p1 == s.length()) {
                return true;
            }
        }
        return false;
    }
}

3Sum.solution:
class Solution {
    public List<List<Integer>> threeSum(int[] nums) {
        Arrays.sort(nums);
        List<List<Integer>> list = new ArrayList<>();
        for (int i = 0; i < nums.length; i++) {
            if (nums[i] > 0) {
                break;
            }
            if(i > 0 && nums[i] == nums[i-1]) {
                continue;
            }
            int left = i + 1;
            int right = nums.length - 1;
            while (left < right) {
                int sum = nums[i] + nums[left] + nums[right];
                if (sum > 0) {
                    right--;
                } else if (sum < 0) {
                    left++;
                } else {
                    list.add(Arrays.asList(nums[i], nums[left], nums[right]));
                    left++;
                    right--;
                    while (left < right && nums[left] == nums[left - 1]) {
                        left++;
                    }
                }
            }
        }
        return list;
    }
}

The kth Factor of n.solution:
class Solution {
    public int kthFactor(int n, int k) {
        int count = 0;
        //counts our current position
        for (int i = 1; i <= n; i++) {
            if (n % i == 0) {
                //increases our counter if we are a kth factor
                count++;
                //if count reaches k then it returns the current position
                if (count == k) {
                    return i;
                }
            }
        }
        //returns -1 if we cannot count != k
        return -1;
    }
}
